init_eqs:
t0a = time; t0 = time+.5;
spb_ = .5; ;
volb = .5; volx = .5;
vol_= 1; index = 0; mov1 = 0;
sdev = .1; wamp_ = .1;

frame_eqs:
dec_med = pow (0.8, 30/fps); dec_slow = pow (0.95, 30/fps);
vol = (bass+med+treb)/1.5; vol_ = vol_*dec_slow + (1-dec_slow)*vol;

is_beat = above(vol, vol_+2*peak) * above (time, t0+spb_*.45);
t0a  = if(is_beat,t0,t0a); t0 = if(is_beat,time,t0);
peak = if(is_beat,vol,peak*dec_med);
index = (index + is_beat) %128;

spb = min(t0-t0a + .01,2);
spb_ = if(is_beat,spb_ *.9 +.1*spb, spb_);


q20 = vol_;
q21 = above(vol,2.7*vol_);
q22 = max(0,peak-.0)+.01;
hpeak = hpeak*dec_med + (1-dec_med)*q21;
q23 = hpeak * (1+rand(8));
q24 = is_beat;
q25 = q22*(1+rand(8))/8;

mindev = min(min(abs(spb-spb_),abs(spb*2-spb_)),abs(spb-spb_*2));
sdev = if(is_beat,sdev * .8 + .2*pow(mindev+.02,2),sdev);

speed = 1/fps/spb_;
trel = trel + speed;
q10 = trel;

wamp =  min(.001/sdev,.15);
wamp_ = wamp_*dec_slow + (1-dec_slow)*wamp;
q11 = sin(trel/2)*wamp_;
q12 = wamp_/2;

rota = 2*wamp_*sin(trel/3);
//rota = .2*sin(wamp_*32);
q5 = cos(rota);
q6 = sin(rota);
q7 = -q6;
q8 = q5;

q15 = -sin(trel*.5)*.05;
q16 = cos(trel)*wamp_/2;

q19 = .1*sin(trel/12);

//ODD PLANET MOVEMENT
trig1 = bnot(vis)*bnot(rand(100*fps));
vis = if (trig1,1,vis*below(mov1,1));
q30 = vis;
mov1 = if (vis,mov1+2*speed/fps,-1);
dir = if(trig1,rand(100),dir);
q31 = .5+.5*cos(dir)*mov1;
q32 = .5+.5*sin(dir)*mov1;

q29 = (2+sin(time/17)); //reflection water

monitor = wamp;

